            m_SimulationDC = dependencies.SimulationDC;
        }

        public override void OnEnter()
        {
            Debug.Log("[AegisFlow] Enter ProcedureSimulationEditor.");

            // [扩展点] 打开编辑态 UI / RTE，绑定 Presenter。
