using AegisFlow.Data;
using AegisFlow.Domain;
using AegisFlow.Runtime;

namespace AegisFlow.Application
{
    /// <summary>
    /// 仿真用例编排服务。负责协调领域层与运行态，不直接操作 UI。
    /// </summary>
    public sealed class SimulationAppService
    {
        private readonly ModelDomainService m_ModelDomainService;
        private readonly RuntimeSnapshotService m_RuntimeSnapshotService;
        private readonly SimulationRuntimeController m_RuntimeController;

        public SimulationAppService(
            ModelDomainService modelDomainService,
            RuntimeSnapshotService runtimeSnapshotService,
            SimulationRuntimeController runtimeController)
        {
            m_ModelDomainService = modelDomainService;
            m_RuntimeSnapshotService = runtimeSnapshotService;
            m_RuntimeController = runtimeController;
        }

        public bool StartRuntime(string modelId)
        {
            if (!m_ModelDomainService.CanRun(modelId))
            {
                return false;
            }

            RuntimeSnapshot snapshot = m_RuntimeSnapshotService.BuildSnapshot(modelId);
            m_RuntimeController.Load(snapshot);
            return true;
        }

        public bool RetryFailedEvent()
        {
            return m_RuntimeController.RetryFailedEvent();
        }

        public bool SkipFailedEvent()
        {
            return m_RuntimeController.SkipFailedEvent();
        }

        public bool TerminateFailedRuntime()
        {
            return m_RuntimeController.TerminateFailedRuntime();
        }
    }
}

using AegisFlow.Data;
using AegisFlow.Save;

namespace AegisFlow.Application
{
    /// <summary>
    /// 仿真模型应用服务。负责编辑态模型保存与加载编排。
    /// </summary>
    public sealed class SimulationModelAppService
    {
        private readonly ModelRepository m_ModelRepository;
        private readonly EntityRepository m_EntityRepository;
        private readonly SimulationDC m_SimulationDC;
        private readonly ISaveJsonAdapter m_SaveJsonAdapter;

        public SimulationModelAppService(
            ModelRepository modelRepository,
            EntityRepository entityRepository,
            SimulationDC simulationDC,
            ISaveJsonAdapter saveJsonAdapter)
        {
            m_ModelRepository = modelRepository;
            m_EntityRepository = entityRepository;
            m_SimulationDC = simulationDC;
            m_SaveJsonAdapter = saveJsonAdapter;
        }

        public bool SaveCurrentModel()
        {
            if (string.IsNullOrEmpty(m_SimulationDC.CurrentModelId))
            {
                return false;
            }

            string modelId = m_SimulationDC.CurrentModelId;
            SimulationModelSaveData saveData = new SimulationModelSaveData(modelId, false, m_EntityRepository.GetAll());

            if (!SaveAppService.Save(BuildSaveKey(modelId), m_SaveJsonAdapter.ToJson(saveData)))
            {
                return false;
            }

            m_ModelRepository.Add(modelId);
            m_SimulationDC.MarkSaved();
            return true;
        }

        public bool LoadModel(string modelId)
        {
            if (string.IsNullOrEmpty(modelId))
            {
                return false;
            }

            string saveKey = BuildSaveKey(modelId);

            if (!TryLoadSaveData(saveKey, modelId, out SimulationModelSaveData saveData))
            {
                return false;
            }

            m_EntityRepository.Clear();

            for (int i = 0; i < saveData.Entities.Count; i++)
            {
                m_EntityRepository.Add(saveData.Entities[i]);
            }

            m_ModelRepository.Add(saveData.ModelId);
            m_SimulationDC.SwitchModel(saveData.ModelId);
            return true;
        }

        private bool TryLoadSaveData(string saveKey, string expectedModelId, out SimulationModelSaveData saveData)
        {
            saveData = null;

            if (SaveAppService.TryLoad(saveKey, out string json)
                && TryParseMatchingModel(json, expectedModelId, out saveData))
            {
                return true;
            }

            return SaveAppService.TryLoadBackup(saveKey, out string backupJson)
                && TryParseMatchingModel(backupJson, expectedModelId, out saveData);
        }

        private bool TryParseMatchingModel(string json, string expectedModelId, out SimulationModelSaveData saveData)
        {
            saveData = null;

            return !string.IsNullOrEmpty(json)
                && m_SaveJsonAdapter.TryFromJson(json, out saveData)
                && saveData.ModelId == expectedModelId;
        }

        private string BuildSaveKey(string modelId)
        {
            return $"simulation_{modelId}";
        }
    }
}

using AegisFlow.Data;

namespace AegisFlow.Application
{
    /// <summary>
    /// 运行态快照服务。负责将编辑态数据转换为运行态快照。
    /// </summary>
    public sealed class RuntimeSnapshotService
    {
        private readonly EntityRepository m_EntityRepository;

        public RuntimeSnapshotService(EntityRepository entityRepository)
        {
            m_EntityRepository = entityRepository;
        }

        public RuntimeSnapshot BuildSnapshot(string modelId)
        {
            RuntimeSnapshot snapshot = new RuntimeSnapshot(modelId);

            foreach (EntityData entityData in m_EntityRepository.GetAll())
            {
                snapshot.AddEntity(entityData.Clone());
            }

            return snapshot;
        }
    }
}

using System.Collections.Generic;

namespace AegisFlow.Data
{
    /// <summary>
    /// 实体仓储。只做数据容器，不做业务规则、不刷新 UI。
    /// </summary>
    public sealed class EntityRepository
    {
        private readonly Dictionary<string, EntityData> m_EntityDic = new Dictionary<string, EntityData>();

        public bool Exists(string entityId)
        {
            return !string.IsNullOrEmpty(entityId) && m_EntityDic.ContainsKey(entityId);
        }

        public void Add(EntityData entityData)
        {
            m_EntityDic[entityData.EntityId] = entityData;
        }

        public bool Remove(string entityId)
        {
            return m_EntityDic.Remove(entityId);
        }

        public EntityData Get(string entityId)
        {
            m_EntityDic.TryGetValue(entityId, out EntityData entityData);
            return entityData;
        }

        public IEnumerable<EntityData> GetAll()
        {
            return m_EntityDic.Values;
        }

        public void Clear()
        {
            m_EntityDic.Clear();
        }
    }
}

using System.Collections.Generic;

namespace AegisFlow.Data
{
    /// <summary>
    /// 模型仓储。只保存模型元数据，不处理模型业务规则。
    /// </summary>
    public sealed class ModelRepository
    {
        private readonly HashSet<string> m_ModelIds = new HashSet<string>();

        public bool Exists(string modelId)
        {
            return !string.IsNullOrEmpty(modelId) && m_ModelIds.Contains(modelId);
        }

        public void Add(string modelId)
        {
            if (!string.IsNullOrEmpty(modelId))
            {
